import type {
  ElementType,
  JSXElementConstructor,
  PropsWithChildren,
  ReactElement,
} from 'react';
import { cloneElement } from 'react';

import type { IntentProps } from '../../../../../core/slots/Intent/Intent.js';
import type { MenuItemProps } from '../../../../../navigation/menu/Item.js';
import { Prefix } from '../../../../../navigation/menu/Prefix.js';
import { Intent } from '../Intent.js';

export const CustomActions = ({
  actions,
}: {
  actions?: ReactElement<
    PropsWithChildren<MenuItemProps<ElementType>>,
    string | JSXElementConstructor<unknown>
  >[];
}) => (
  <>
    {actions?.map((action, index) =>
      cloneElement(action, { key: action.key ?? index }),
    )}
  </>
);

export const CustomIntents = ({
  intents,
}: {
  intents?: ReactElement<
    PropsWithChildren<IntentProps>,
    string | JSXElementConstructor<unknown>
  >[];
}) => (
  <>
    {intents?.map((intent, index) => (
      <Intent key={intent.key ?? index} {...intent.props}>
        {intent.props.icon && (
          <Prefix>{intent.props.icon}</Prefix>
        )}
        {intent.props.children}
      </Intent>
    ))}
  </>
);
